const sections = variables['b9a35e20-eca6-4130-88a8-2da153cef719']?.data?.data ?? [];
const allPlates = variables['4e99116a-724e-42c6-9401-140a54bac5c5'] ?? [];
const allDrinks = variables['16fdba67-5b9f-484f-9f0e-e3b83bdc48cd'] ?? [];

const plateAllergens = allPlates
  .flatMap(p => p.products ?? [])
  .flatMap(p => p.allergens ?? []);

const drinkAllergens = allDrinks
  .flatMap(d => d.allergens ?? []);

const allergens = [
  ...new Map(
    [...plateAllergens, ...drinkAllergens]
      .map(a => [a.id, a])
  ).values()
];

const priority = [1, 7];
return [
  ...allergens.filter(a => priority.includes(a.id)),
  ...allergens.filter(a => !priority.includes(a.id)),
];

